## API Route Security Template

For every API route in `src/app/api/`:

```typescript
// src/app/api/tenants/[tenantId]/messages/route.ts
export async function GET(
  request: Request,
  { params }: { params: { tenantId: string } }
) {
  try {
    // 1. Validate tenantId format
    if (!isValidUUID(params.tenantId)) {
      return NextResponse.json({ error: 'Invalid tenant ID' }, { status: 400 });
    }

    // 2. Authenticate user
    const supabase = createServerClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // 3. Verify tenant ownership
    const { data: tenant, error: tenantError } = await supabase
      .from('tenants')
      .select('id')
      .eq('id', params.tenantId)
      .eq('user_id', user.id)  // ← CRITICAL: Verify ownership
      .single();

    if (tenantError || !tenant) {
      return NextResponse.json({ error: 'Tenant not found or access denied' }, { status: 403 });
    }

    // 4. Query with explicit tenant filter
    const { data: messages, error } = await supabase
      .from('messages')
      .select(`
        id,
        content,
        role,
        created_at,
        conversations!inner (
          tenant_id
        )
      `)
      .eq('conversations.tenant_id', params.tenantId)  // ← Explicit filter
      .order('created_at', { ascending: false })
      .limit(50);

    // 5. Sanitize response (remove PII if not needed)
    const sanitized = messages?.map(msg => ({
      id: msg.id,
      content: msg.content.substring(0, 100), // Truncate for lists
      role: msg.role,
      time: msg.created_at
    }));

    return NextResponse.json({ messages: sanitized });

  } catch (error) {
    console.error('Messages API error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
```

