'use client';

import { useState, useEffect } from 'react';
import { useParams } from 'next/navigation';
import styles from './ChatTab.module.css';

interface Message {
  id: string;
  role: 'user' | 'assistant' | 'owner';
  content: string;
  is_from_agent: boolean;
  created_at: string;
  media_url?: string;
  media_type?: string;
}

interface Conversation {
  id: string;
  phone_number: string;
  contact_name: string | null;
  is_group: boolean;
  updated_at: string;
  last_message?: string;
  unread_count?: number;
  messages?: Message[];
}

export default function ChatTab() {
  const params = useParams();
  const tenantId = params.id as string;

  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [messagesLoading, setMessagesLoading] = useState(false);

  // Fetch conversations (newest first)
  useEffect(() => {
    const fetchConversations = async () => {
      try {
        setLoading(true);
        const response = await fetch(`/api/tenants/${tenantId}/conversations`);

        if (!response.ok) {
          throw new Error('Failed to fetch conversations');
        }

        const data = await response.json();

        // Backend should return conversations sorted by updated_at DESC (newest first)
        setConversations(data.conversations || []);

        // Auto-select first conversation if available
        if (data.conversations?.length > 0 && !selectedConversation) {
          setSelectedConversation(data.conversations[0]);
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
        console.error('Error fetching conversations:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchConversations();
  }, [tenantId]);

  // Fetch messages for selected conversation (oldest first)
  useEffect(() => {
    const fetchMessages = async () => {
      if (!selectedConversation) return;

      try {
        setMessagesLoading(true);
        const response = await fetch(
          `/api/tenants/${tenantId}/conversations/${selectedConversation.id}/messages`
        );

        if (!response.ok) {
          throw new Error('Failed to fetch messages');
        }

        const data = await response.json();

        // Backend should return messages sorted by created_at ASC (oldest first)
        const updatedConversation = {
          ...selectedConversation,
          messages: data.messages || []
        };

        setSelectedConversation(updatedConversation);

        // Update conversations list with latest message preview
        setConversations(prev => prev.map(conv => 
          conv.id === selectedConversation.id 
            ? { ...conv, last_message: data.messages?.[data.messages.length - 1]?.content }
            : conv
        ));
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
        console.error('Error fetching messages:', err);
      } finally {
        setMessagesLoading(false);
      }
    };

    fetchMessages();
  }, [selectedConversation?.id, tenantId]);

  // Scroll to bottom of messages when new messages load
  useEffect(() => {
    if (selectedConversation?.messages && selectedConversation.messages.length > 0) {
      const messagesContainer = document.getElementById('messages-container');
      if (messagesContainer) {
        messagesContainer.scrollTop = messagesContainer.scrollHeight;
      }
    }
  }, [selectedConversation?.messages]);

  const formatTime = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleTimeString('he-IL', { 
      hour: '2-digit', 
      minute: '2-digit',
      hour12: false 
    });
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);

    if (date.toDateString() === today.toDateString()) {
      return 'היום';
    } else if (date.toDateString() === yesterday.toDateString()) {
      return 'אתמול';
    } else {
      return date.toLocaleDateString('he-IL');
    }
  };

  const getContactDisplayName = (conversation: Conversation) => {
    if (conversation.contact_name) {
      return conversation.contact_name;
    }
    if (conversation.is_group) {
      return `קבוצה: ${conversation.phone_number}`;
    }
    return conversation.phone_number;
  };

  if (loading) {
    return (
      <div className={styles.loadingContainer}>
        <div className={styles.spinner}></div>
        <p>טוען שיחות...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className={styles.errorContainer}>
        <p className={styles.errorText}>{error}</p>
        <button 
          className={styles.retryButton}
          onClick={() => window.location.reload()}
        >
          נסה שוב
        </button>
      </div>
    );
  }

  return (
    <div className={styles.chatContainer}>
      {/* Conversations sidebar */}
      <div className={styles.conversationsSidebar}>
        <div className={styles.sidebarHeader}>
          <h2>שיחות</h2>
          <span className={styles.conversationCount}>
            {conversations.length} שיחות
          </span>
        </div>

